package com.funkyotc.puzzleverse.cubeshooter.data

import com.funkyotc.puzzleverse.core.data.BrowseablePuzzle

data class PregeneratedLevel(
    override val id: String,
    override val difficulty: String,
    val cols: Int,
    val rows: Int,
    val grid: List<List<Int?>>,
    val tray: List<Tank>
) : BrowseablePuzzle {
    override val label: String get() = id.substringAfterLast('_')
    override val subtitle: String get() = "${cols}x${rows}"
}

object CubeShooterPregenerated {

    private fun parseLevel(
        id: String, difficulty: String, cols: Int, rows: Int,
        grid: String, tray: String
    ): PregeneratedLevel {
        val parsedGrid = grid.split('|').map { row ->
            row.split(',').map { it.toIntOrNull() }
        }
        val parsedTray = tray.split(';').map { part ->
            val (c, a) = part.split(',').map { it.toInt() }
            Tank(c, a)
        }
        return PregeneratedLevel(id, difficulty, cols, rows, parsedGrid, parsedTray)
    }

